const row = (($json.body || [])[0]) || { daily_cost_usd: 0, monthly_cost_usd: 0, daily_call_count: 0, monthly_call_count: 0 };
const daily = Number(row.daily_cost_usd) || 0;
const monthly = Number(row.monthly_cost_usd) || 0;
const dailyLimit = Number($env.AI_BUDGET_DAILY_USD || 2);
const monthlyLimit = Number($env.AI_BUDGET_MONTHLY_USD || 50);
const dailyPct = dailyLimit > 0 ? daily / dailyLimit : 0;
const monthlyPct = monthlyLimit > 0 ? monthly / monthlyLimit : 0;
const dailyExceeded = daily >= dailyLimit;
const monthlyExceeded = monthly >= monthlyLimit;
const dailyWarn = !dailyExceeded && dailyPct >= 0.8;
const monthlyWarn = !monthlyExceeded && monthlyPct >= 0.8;
const alert = dailyExceeded || monthlyExceeded || dailyWarn || monthlyWarn;
let severity = 'info';
if (dailyExceeded || monthlyExceeded) severity = 'exceeded';
else if (dailyWarn || monthlyWarn) severity = 'warn';
return [{ json: {
  daily_cost_usd: daily,
  monthly_cost_usd: monthly,
  daily_call_count: Number(row.daily_call_count) || 0,
  monthly_call_count: Number(row.monthly_call_count) || 0,
  daily_limit_usd: dailyLimit,
  monthly_limit_usd: monthlyLimit,
  daily_pct: Number((dailyPct * 100).toFixed(1)),
  monthly_pct: Number((monthlyPct * 100).toFixed(1)),
  daily_exceeded: dailyExceeded,
  monthly_exceeded: monthlyExceeded,
  alert: alert,
  severity: severity,
  run_at: new Date().toISOString()
} }];
